<script>
function hrError(m){$('.isi_warning_delete').text(m||'Hiring gagal diproses.');$('.error_data_delete').fadeIn();}
function hrFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),hiring_status:$('#filter_hiring_status').val(),offer_status:$('#filter_offer_status').val(),onboarding_status:$('#filter_onboarding_status').val(),vacancy_id:$('#filter_vacancy_id').val(),keyword:$('#filter_keyword').val()};}
function hrSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return;}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change');}
function ajaxSel(s,act,ph,parent){$(s).select2({width:'100%',allowClear:true,placeholder:ph,dropdownParent:parent||$(document.body),ajax:{url:'<?=base_admin();?>modul/hiring/hiring_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
function nextNo(){ $.post('<?=base_admin();?>modul/hiring/hiring_action.php?act=next_no',{year:($('#hiring_date').val()||'<?=date('Y');?>').substr(0,4)},function(r){if(r.status==='good')$('#hiring_no').val(r.hiring_no);},'json');}
function resetHr(t){$('#form_hr')[0].reset();$('#hr_id').val('');$('#hiring_date').val('<?=date('Y-m-d');?>');$('#hiring_status').val('DRAFT').trigger('change');$('#offer_status').val('NOT_CREATED').trigger('change');$('#onboarding_status').val('NOT_STARTED').trigger('change');$('#contract_status').val('NOT_PREPARED').trigger('change');$('#document_status').val('PENDING').trigger('change');$('#medical_check_status').val('NOT_REQUIRED').trigger('change');$('#background_check_status').val('NOT_REQUIRED').trigger('change');$('#hiring_type').val('NEW_HIRE').trigger('change');$('#employment_type').val('PERMANENT').trigger('change');$('#employee_group').val('STAFF').trigger('change');$('#currency').val('IDR').trigger('change');$('#selection_result_id,#applicant_id,#vacancy_id,#hired_employee_id,#proposed_position_id,#proposed_job_title_id,#recruiter_employee_id,#hiring_manager_employee_id,#hr_pic_employee_id').val(null).trigger('change');$('#salary_amount,#checklist_total,#checklist_done').val(0);$('#probation_months').val(3);$('#modal_hr .modal-title').text(t||'Create Hiring');nextNo();}
$(function(){if($.fn.datepicker){$('.hr-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_hiring_status,#filter_offer_status,#filter_onboarding_status,#hiring_status,#offer_status,#onboarding_status,#contract_status,#document_status,#medical_check_status,#background_check_status,#hiring_type,#employment_type,#employee_group,#currency').select2({width:'100%',allowClear:true});ajaxSel('#filter_vacancy_id','vacancy_search','Semua Vacancy');ajaxSel('#selection_result_id','selection_search','Pilih Selection Result',$('#modal_hr'));ajaxSel('#applicant_id','applicant_search','Pilih Applicant',$('#modal_hr'));ajaxSel('#vacancy_id','vacancy_search','Pilih Vacancy',$('#modal_hr'));ajaxSel('#hired_employee_id','employee_search','Pilih Employee',$('#modal_hr'));ajaxSel('#proposed_position_id','position_search','Pilih Position',$('#modal_hr'));ajaxSel('#proposed_job_title_id','job_title_search','Pilih Job Title',$('#modal_hr'));ajaxSel('#recruiter_employee_id','employee_search','Pilih Recruiter',$('#modal_hr'));ajaxSel('#hiring_manager_employee_id','employee_search','Pilih Hiring Manager',$('#modal_hr'));ajaxSel('#hr_pic_employee_id','employee_search','Pilih HR PIC',$('#modal_hr'));}
var dt=$('#dtb_hiring').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{targets:[9],className:'text-right'},{width:'42px',targets:0},{width:'160px',targets:1}],ajax:{url:'<?=base_admin();?>modul/hiring/hiring_data.php',type:'post',data:function(d){$.extend(d,hrFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_accepted').text(k.accepted||0);$('#kpi_hired').text(k.hired||0);$('#kpi_onboarded').text(k.onboarded||0);$('#kpi_failed').text(k.failed||0);$('#kpi_progress').text(k.progress||0);return j.data||[];},error:function(xhr){console.log(xhr.responseText);hrError('Data Hiring gagal dimuat.');}}});
$('#btn_open_hr').click(function(){resetHr('Create Hiring');$('#modal_hr').modal({backdrop:'static',keyboard:false});});$('#btn_next_hr,#hiring_date').on('click change',nextNo);$('#btn_filter_hr').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_hr').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_hiring_status,#filter_offer_status,#filter_onboarding_status,#filter_vacancy_id').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_hr').click(function(){window.location='<?=base_admin();?>modul/hiring/hiring_action.php?act=export&'+$.param(hrFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
$('#selection_result_id').on('select2:select',function(e){$.post('<?=base_admin();?>modul/hiring/hiring_action.php?act=selection_info',{id:e.params.data.id},function(r){if(r.status!=='good')return;var d=r.data||{};hrSet('#applicant_id',d.applicant_id,d.applicant_text);hrSet('#vacancy_id',d.vacancy_id,d.vacancy_text);hrSet('#proposed_position_id',d.proposed_position_id,d.position_text);hrSet('#proposed_job_title_id',d.proposed_job_title_id,d.job_title_text);hrSet('#recruiter_employee_id',d.recruiter_employee_id,d.recruiter_text);hrSet('#hiring_manager_employee_id',d.hiring_manager_employee_id,d.manager_text);hrSet('#hr_pic_employee_id',d.recruiter_employee_id,d.recruiter_text);$('#planned_join_date').val(d.planned_join_date||'');$('#employment_type').val(d.employment_type||'PERMANENT').trigger('change');$('#employee_group').val(d.employee_group||'STAFF').trigger('change');$('#department_code').val(d.department_code||'');$('#company_structure_id').val(d.company_structure_id||'');$('#work_location_id').val(d.work_location_id||'');$('#cost_center_code').val(d.cost_center_code||'');$('#profit_center_code').val(d.profit_center_code||'');$('#pay_grade').val(d.pay_grade||'');$('#salary_amount').val(d.salary_amount||0);$('#currency').val(d.currency||'IDR').trigger('change');},'json');});
$('#form_hr').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/hiring/hiring_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Hiring');if(r.status==='good'){$('#modal_hr').modal('hide');dt.draw(false);Swal.fire('Saved','Hiring berhasil disimpan.','success');}else hrError(r.error_message);},'json').fail(function(xhr){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Hiring');hrError(xhr.responseText);});});
$(document).on('click','.btn-hd-detail',function(){$.post('<?=base_admin();?>modul/hiring/hiring_action.php?act=detail',{id:$(this).data('id')},function(h){$('#hr_detail_body').html(h);$('#modal_hr_detail').modal('show');});});
$(document).on('click','.btn-hd-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/hiring/hiring_action.php?act=get',{id:id},function(r){if(r.status!=='good'){hrError(r.error_message);return;}resetHr('Edit Hiring');var h=r.data||{};Object.keys(h).forEach(function(k){var el=$('#'+k);if(el.length&&!['selection_result_id','applicant_id','vacancy_id','hired_employee_id','proposed_position_id','proposed_job_title_id','recruiter_employee_id','hiring_manager_employee_id','hr_pic_employee_id'].includes(k))el.val(h[k]);});$('#hr_id').val(h.id);hrSet('#selection_result_id',h.selection_result_id,h.selection_text);hrSet('#applicant_id',h.applicant_id,h.applicant_text);hrSet('#vacancy_id',h.vacancy_id,h.vacancy_text);hrSet('#hired_employee_id',h.hired_employee_id,h.employee_text);hrSet('#proposed_position_id',h.proposed_position_id,h.position_text);hrSet('#proposed_job_title_id',h.proposed_job_title_id,h.job_title_text);hrSet('#recruiter_employee_id',h.recruiter_employee_id,h.recruiter_text);hrSet('#hiring_manager_employee_id',h.hiring_manager_employee_id,h.manager_text);hrSet('#hr_pic_employee_id',h.hr_pic_employee_id,h.pic_text);$('#hiring_status,#offer_status,#onboarding_status,#contract_status,#document_status,#medical_check_status,#background_check_status,#hiring_type,#employment_type,#employee_group,#currency').trigger('change');$('#modal_hr').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-hd-status',function(){var id=$(this).data('id'),status=$(this).data('status');$.post('<?=base_admin();?>modul/hiring/hiring_action.php?act=status',{id:id,status:status},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Updated','Status berhasil diubah.','success');}else hrError(r.error_message);},'json');});
$(document).on('click','.btn-hd-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/hiring/hiring_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else hrError(r.error_message);},'json');});});
});
</script>
